// Mike's Cookbook — Service Worker
// Relative-path precache so the app works at any GitHub Pages project subpath.
// The CACHE_URLS list is generated by tools/build-sw.py — do not edit by hand.

const CACHE_NAME = 'mc-cookbook-v24';

const CACHE_URLS = [
  /* AUTOGEN:URLS START */
  './',
  './index.html',
  './collection.html',
  './collection.js',
  './cookbook-home.js',
  './cookbook-nav.js',
  './cookbook-sw.js',
  './cookbook.css',
  './cookbook.js',
  './icon.svg',
  './manifest.json',
  './mc-account.js',
  './mc-backup-status.js',
  './mc-bridge.js',
  './mc-export.js',
  './mc-install.js',
  './mc-supabase.js',
  './mc-sync.js',
  './quick-tour-overview.html',
  './quick-tour.html',
  './recipe.html',
  './recipes-data.js',
  './tracker-barcode.js',
  './tracker-calc.js',
  './tracker-foodapi.js',
  './tracker-recipe.js',
  './tracker-store.js',
  './tracker.js',
  './user-recipes.js',
  /* AUTOGEN:URLS END */
];

self.addEventListener('install', (event) => {
  // Activate a new version immediately rather than waiting for a manual Refresh.
  // Paired with clients.claim() on activate and the page's controllerchange
  // reload, this guarantees fixes reach users on the next visit without a tap.
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(CACHE_URLS))
  );
});

// The page asks the waiting worker to take over (user tapped Refresh).
self.addEventListener('message', (event) => {
  if (event.data && event.data.type === 'SKIP_WAITING') self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(
        keys.filter((k) => k !== CACHE_NAME).map((k) => caches.delete(k))
      ))
      .then(() => self.clients.claim())
  );
});

// HTML: stale-while-revalidate (audit LS-4, W-12). Serve the cached page
// INSTANTLY when we have one — navigations feel instant on flaky kitchen
// Wi-Fi instead of waiting up to 3s — and refresh the cache behind for next
// load. Cache-first is correct because this is a static site whose content
// only changes on a deploy, which bumps CACHE_NAME (the activate handler above
// purges the old cache and cookbook-sw.js reloads on controllerchange), so a
// new build always reaches the cook via the SW-version path. First visits
// (nothing cached) fall through to the network, then the app shell.
// Everything else: cache-first, then network (unchanged — already instant).
self.addEventListener('fetch', (event) => {
  const req = event.request;
  if (req.method !== 'GET') return;

  const isHTML = req.mode === 'navigate' ||
    (req.headers.get('accept') || '').includes('text/html');

  if (isHTML) {
    const revalidation = fetch(req).then((res) => {
      if (res && res.status === 200) {
        const copy = res.clone();
        caches.open(CACHE_NAME).then((c) => c.put(req, copy));
      }
      return res;
    }).catch(() => null);
    event.waitUntil(revalidation.catch(() => {}));
    event.respondWith(
      caches.match(req).then((cached) =>
        cached || revalidation.then((res) => res || caches.match('./index.html'))
      )
    );
    return;
  }

  event.respondWith(
    caches.match(req).then((cached) =>
      cached || fetch(req).then((res) => {
        const copy = res.clone();
        caches.open(CACHE_NAME).then((c) => c.put(req, copy));
        return res;
      }).catch(() => cached)
    )
  );
});
